        // Guarantees interpolation never takes the long way around 0/2ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬ÃƒÂ¢Ã¢â‚¬Å¾Ã‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚ÂÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â¦ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬.
        inline float lerpAngle(float current, float target, float alpha)
        {
            constexpr float TWO_PI = 6.28318530718f;
            constexpr float PI = 3.14159265359f;
            float diff = target - current;
            while (diff > PI)
                diff -= TWO_PI;
            while (diff < -PI)
                diff += TWO_PI;
            return current + diff * alpha;
        }

        float distanceSquared3(float ax, float ay, float az, const Position& position)
        {
            const float dx = position.pos[0] - ax;
            const float dy = position.pos[1] - ay;
            const float dz = position.pos[2] - az;
            return dx * dx + dy * dy + dz * dz;
        }

        uint64_t steadyTimeMs()
        {
            return static_cast<uint64_t>(std::chrono::duration_cast<std::chrono::milliseconds>(
                std::chrono::steady_clock::now().time_since_epoch()).count());
        }

        uint64_t steadyTimeUs()
        {
            return static_cast<uint64_t>(std::chrono::duration_cast<std::chrono::microseconds>(
                std::chrono::steady_clock::now().time_since_epoch()).count());
        }

        void clearTransientLocomotion(AnimFlags& flags)
        {
            flags.animFwd = 0.f;
            flags.animSide = 0.f;
            flags.blockedMoveSpeed = 0.f;
            flags.jumpVz = 0.f;
            flags.movementFlags &= ~AnimFlags::MF_WALL_BLOCKED;
            flags.actionFlags &= (AnimFlags::AF_WEAPON_DRAWN | AnimFlags::AF_SPELL_READY);
        }

        bool isUnarmedAttack(const MWWorld::Ptr& attacker)
        {
            if (attacker.isEmpty() || !attacker.getClass().hasInventoryStore(attacker))
                return true;

            const MWWorld::InventoryStore& inv = attacker.getClass().getInventoryStore(attacker);
            const MWWorld::ConstContainerStoreIterator weapon = inv.getSlot(MWWorld::InventoryStore::Slot_CarriedRight);
            return weapon == inv.end() || weapon->getType() != ESM::Weapon::sRecordId;
        }

        MWWorld::Ptr getEquippedWeapon(const MWWorld::Ptr& attacker)
        {
            if (attacker.isEmpty() || !attacker.getClass().hasInventoryStore(attacker))
                return {};

            MWWorld::InventoryStore& inv = attacker.getClass().getInventoryStore(attacker);
            MWWorld::ContainerStoreIterator weapon = inv.getSlot(MWWorld::InventoryStore::Slot_CarriedRight);
            if (weapon == inv.end() || weapon->getType() != ESM::Weapon::sRecordId)
                return {};

            return *weapon;
        }

        void playReplicatedOnStrikeEnchantment(
            const MWWorld::Ptr& attacker, const MWWorld::Ptr& target, const std::string& enchantmentId)
        {
            if (enchantmentId.empty() || attacker.isEmpty() || target.isEmpty())
                return;

            const auto& esmStore = *MWBase::Environment::get().getESMStore();
            const ESM::Enchantment* enchantment
                = esmStore.get<ESM::Enchantment>().search(ESM::RefId::stringRefId(enchantmentId));
            if (!enchantment || enchantment->mData.mType != ESM::Enchantment::WhenStrikes)
                return;

            const auto& effectStore = esmStore.get<ESM::MagicEffect>();
            for (const auto& effectInfo : enchantment->mEffects.mList)
            {
                const ESM::MagicEffect* effect = effectStore.search(effectInfo.mData.mEffectID);
                if (!effect)
                    continue;

                const MWWorld::Ptr& effectTarget
                    = effectInfo.mData.mRange == ESM::RT_Self ? attacker : target;
                MWMechanics::playEffects(effectTarget, *effect);
            }
        }

        MWWorld::CellStore* findActiveCell(MWWorld::World& world, const CellId& cellState)
        {
            auto& scene = world.getWorldScene();
            for (MWWorld::CellStore* store : scene.getActiveCells())
            {
                if (store == nullptr)
                    continue;

                const MWWorld::Cell* cell = store->getCell();
                if (cell == nullptr)
                    continue;

                if (cellState.isExterior)
                {
                    if (cell->isExterior() && cell->getGridX() == cellState.gridX && cell->getGridY() == cellState.gridY)
                        return store;
                }
                else if (!cell->isExterior() && std::string(cell->getNameId()) == cellState.cellName)
                {
                    return store;
                }
            }

            return nullptr;
        }

        bool sameCosmeticItem(const Item& left, const Item& right)
        {
            return left.refId == right.refId && left.count == right.count;
        }

        bool sameCosmeticInventory(const std::vector<Item>& left, const std::vector<Item>& right)
        {
            if (left.size() != right.size())
                return false;

            for (std::size_t i = 0; i < left.size(); ++i)
            {
                if (!sameCosmeticItem(left[i], right[i]))
                    return false;
            }

            return true;
        }

        bool equipmentSlotsMatchState(
            MWWorld::InventoryStore& inv,
            const std::array<EquipmentItem, BasePlayer::NUM_EQUIPMENT_SLOTS>& equipment)
        {
            for (int slot = 0; slot < BasePlayer::NUM_EQUIPMENT_SLOTS; ++slot)
            {
                const std::string& targetRefId = equipment[slot].item.refId;
                MWWorld::ContainerStoreIterator current = inv.getSlot(slot);
                if (targetRefId.empty())
                {
                    if (current != inv.end())
                        return false;
                    continue;
                }

                if (current == inv.end()
                    || current->getCellRef().getRefId().serializeText() != targetRefId)
                    return false;
            }

            return true;
        }

        void playItemSoundForActor(const MWWorld::Ptr& actor, const Item& item, bool pickedUp)
        {
            if (actor.isEmpty() || item.refId.empty())
                return;

            MWBase::World* world = MWBase::Environment::get().getWorld();
            MWBase::SoundManager* sound = MWBase::Environment::get().getSoundManager();
            if (!world || !sound)
                return;

            MWWorld::ManualRef ref(world->getStore(), ESM::RefId::stringRefId(item.refId), std::max(1, item.count));
            if (ref.getPtr().isEmpty())
                return;

            // A ranged shot is replicated as an inventory decrement for its
            // arrow, bolt, or thrown weapon. Treating that decrement like a
            // manual drop plays Item Ammo Down on observers after every shot.
            // The firing animation already supplies the correct spatial cue.
            if (!pickedUp && ref.getPtr().getType() == ESM::Weapon::sRecordId)
            {
                const int weaponType = ref.getPtr().get<ESM::Weapon>()->mBase->mData.mType;
                if (weaponType == ESM::Weapon::Arrow || weaponType == ESM::Weapon::Bolt
                    || weaponType == ESM::Weapon::MarksmanThrown)
                {
                    return;
                }
            }

            const ESM::RefId& soundId = pickedUp
                ? ref.getPtr().getClass().getUpSoundId(ref.getPtr())
                : ref.getPtr().getClass().getDownSoundId(ref.getPtr());
            if (soundId.empty())
                return;

            sound->playSound3D(actor, soundId, 1.0f, 1.0f);
        }

        bool playInventoryDiffSound(const MWWorld::Ptr& actor,
                                    const std::vector<Item>& oldItems,
                                    const std::vector<Item>& newItems)
        {
            std::unordered_map<std::string, int> oldCounts;
            std::unordered_map<std::string, int> newCounts;

            for (const auto& item : oldItems)
                oldCounts[item.refId] += item.count;
            for (const auto& item : newItems)
                newCounts[item.refId] += item.count;

            for (const auto& [refId, newCount] : newCounts)
            {
                const int oldCount = oldCounts[refId];
                if (newCount > oldCount)
                {
                    Item soundItem;
                    soundItem.refId = refId;
                    soundItem.count = newCount - oldCount;
                    playItemSoundForActor(actor, soundItem, /*pickedUp=*/true);
                    return true;
                }
            }

            for (const auto& [refId, oldCount] : oldCounts)
            {
                const int newCount = newCounts[refId];
                if (oldCount > newCount)
                {
                    Item soundItem;
                    soundItem.refId = refId;
                    soundItem.count = oldCount - newCount;
                    playItemSoundForActor(actor, soundItem, /*pickedUp=*/false);
                    return true;
                }
            }

            return false;
        }

        void playReplicatedImpactSound(const MWWorld::Ptr& attacker, const MWWorld::Ptr& target, const Attack& atk)
        {
            const MWBase::Environment& env = MWBase::Environment::get();
            MWBase::World* world = env.getWorld();
            MWBase::SoundManager* sound = env.getSoundManager();
            if (!world || !sound || target.isEmpty() || !atk.hit)
                return;

            const bool melee = atk.type == 0;
            const bool unarmed = melee && isUnarmedAttack(attacker);
            const bool isWerewolf = !attacker.isEmpty() && unarmed && attacker.getClass().isNpc()
                && attacker.getClass().getNpcStats(attacker).isWerewolf();

            if (isWerewolf)
            {
                const MWWorld::ESMStore& store = world->getStore();
                if (const ESM::Sound* wolfHit = store.get<ESM::Sound>().searchRandom("WolfHit", world->getPrng()))
                    sound->playSound3D(target, wolfHit->mId, 1.0f, 1.0f);
            }
            else if (unarmed && !atk.healthDamage)
            {
                static const std::array<ESM::RefId, 2> h2hSounds = {
                    ESM::RefId::stringRefId("Hand To Hand Hit"),
                    ESM::RefId::stringRefId("Hand To Hand Hit 2"),
                };
                sound->playSound3D(target, h2hSounds[Misc::Rng::rollDice(h2hSounds.size(), world->getPrng())], 1.0f,
                    1.0f);
            }
        }

        void spawnReplicatedPlayerBloodEffect(const MWWorld::Ptr& target, const osg::Vec3f& hitPos)
        {
            MWBase::World* world = MWBase::Environment::get().getWorld();
            if (!world || target.isEmpty())
                return;

            osg::Vec3f effectPos = hitPos;
            if (effectPos.length2() < 0.001f)
                effectPos = target.getRefData().getPosition().asVec3();

            int bloodType = 0;
            if (target.getType() == ESM::NPC::sRecordId)
                bloodType = target.get<ESM::NPC>()->mBase->mBloodType;
            else if (target.getType() == ESM::Creature::sRecordId)
                bloodType = target.get<ESM::Creature>()->mBase->mBloodType;

            const std::size_t bloodModelIndex = Misc::Rng::rollDice(3, world->getPrng());
            const std::string modelKey = "Blood_Model_" + std::to_string(bloodModelIndex);
            const std::string bloodModel = Misc::ResourceHelpers::correctMeshPath(
                VFS::Path::Normalized(Fallback::Map::getString(modelKey)));

            std::string bloodTexture = std::string(Fallback::Map::getString("Blood_Texture_" + std::to_string(bloodType)));
            if (bloodTexture.empty())
                bloodTexture = std::string(Fallback::Map::getString("Blood_Texture_0"));

            world->spawnEffect(VFS::Path::Normalized(bloodModel), bloodTexture, effectPos, 1.f, false, false);
        }

